def _domain_findings(capability: Improve1Capability, payload: dict[str, Any]) -> tuple[str, ...]:
    findings: list[str] = []
    n = capability.feature_number
    if n == 1 and not payload.get("entitlement_lookup"): findings.append("service request triage requires entitlement classification")
    if n == 2 and payload.get("allowed_transition") is not True: findings.append("work order lifecycle transition is blocked")
    if n == 3 and payload.get("staleness_indicator") == "stale" and not payload.get("fallback_behavior"): findings.append("asset projection requires fallback when stale")
    if n == 4 and payload.get("profile_completeness_score", 0) < 0.8: findings.append("technician profile is incomplete for assignment")
    if n == 5 and payload.get("expiry_date", "") < "2026-01-01": findings.append("expired certification cannot satisfy skill assignment")
    if n == 7 and (payload.get("consent_basis") != "active" or payload.get("location_mutation_allowed") is not True): findings.append("live workforce tracking requires active consent")
    if n == 9 and payload.get("hard_constraints") != "satisfied": findings.append("route optimization violated hard constraints")
    if n == 10 and payload.get("dispatcher_approval") is not True: findings.append("dynamic reoptimization requires dispatcher approval")
    if n == 11 and (payload.get("weighted_assignment_score", 0) < payload.get("minimum_threshold", 1) or payload.get("disqualifying_constraints")): findings.append("skill-location-tool assignment score is insufficient")
    if n == 12 and payload.get("policy_violation"): findings.append("fatigue or fairness policy violation requires override")
    if n == 13 and payload.get("capacity_validation") != "passed": findings.append("appointment promise requires capacity validation")
    if n == 16 and payload.get("calibration_status") != "current": findings.append("job tool readiness requires current calibration")
    if n == 17 and (payload.get("blocked_usage") or payload.get("completion_allowed") is not True): findings.append("uncalibrated or unassigned tools block completion")
    if n == 21 and payload.get("safe_merge_decision") not in ("merged", "queued_for_review"): findings.append("offline mobile sync requires safe merge decision")
    if n == 22 and payload.get("blocked_tasks"): findings.append("mobile task dependencies still block execution")
    if n == 23 and payload.get("safety_gate_complete") is not True: findings.append("hazardous task cannot proceed without safety gate")
    if n == 29 and payload.get("approval_status") != "approved" and payload.get("scope_block") != "emergency_override": findings.append("billable field work outside approved quote is blocked")
    if n == 38 and payload.get("contact_confirmation") != "confirmed": findings.append("site readiness requires customer/contact confirmation")
    if n == 42 and payload.get("finance_mutation_blocked") is not True: findings.append("cost-to-serve cannot mutate finance tables")
    if n == 44 and payload.get("fleet_master_mutation_blocked") is not True: findings.append("vehicle readiness must use fleet projection only")
    if n == 45 and (not payload.get("source_citations") or payload.get("confirmation_gate") is not True): findings.append("agent document intake requires citations and confirmation")
    if n == 46 and payload.get("human_confirmation") is not True: findings.append("technician copilot actions require human confirmation")
    if n == 48 and (payload.get("owned_table_mutation_only") is not True or payload.get("outbox_inbox_dead_letter_only") is not True): findings.append("cross-PBC boundary proof failed")
    if n == 49 and (payload.get("retry_dead_letter_tests") != "passed" or payload.get("privacy_consent_tests") != "passed" or payload.get("offline_replay_smoke") != "passed"): findings.append("field release evidence pack is incomplete")
    if n == 50 and not all(payload.get(field) is True for field in ("dispatcher_workbench", "technician_workbench", "supervisor_workbench", "parts_coordinator_workbench", "safety_reviewer_workbench", "customer_support_workbench", "operations_manager_workbench", "executive_sponsor_workbench", "intake_coverage", "work_orders_coverage", "routes_coverage", "live_map_coverage", "skills_coverage", "availability_coverage", "tools_coverage", "parts_coverage", "mobile_tasks_coverage", "safety_gates_coverage", "warranty_coverage", "sla_coverage", "customer_confirmations_coverage", "repeat_visits_coverage", "analytics_coverage", "policies_coverage", "agent_panels_coverage", "release_evidence_coverage")): findings.append("complete field service workbench coverage is incomplete")
    if payload.get("stream_engine_picker_visible"): findings.append("ordinary PBCs must not expose stream-engine pickers")
    return tuple(findings)


def evaluate_field_control(capability: Improve1Capability | str | int, payload: dict[str, Any] | None = None) -> dict[str, Any]:
    resolved = _resolve(capability)
    if resolved is None: return {"ok": False, "reason": "unknown_capability", "side_effects": ()}
    spec = CONTROL_SPECS[resolved.feature_number]
    candidate = sample_payload_for(resolved); candidate.update(dict(payload or {}))
    missing_fields = tuple(field for field in spec["fields"] if field not in _EMPTY_ALLOWED_FIELDS and candidate.get(field) in (None, "", (), []))
    foreign_tables = tuple(table for table in spec["tables"] if table not in FIELD_CONTROL_OWNED_TABLES)
    undeclared_dependencies = tuple(dependency for dependency in spec["dependencies"] if dependency not in FIELD_CONTROL_DECLARED_DEPENDENCIES)
    findings = _domain_findings(resolved, candidate)
    evidence = {"evidence_id": _digest((PBC_KEY, resolved.feature_number, tuple(sorted(candidate))))[:20], "owned_tables": spec["tables"], "required_fields": spec["fields"], "ui_surface": spec["ui"], "service_api": spec["route"], "test": "tests/test_domain_behavior.py", "event_contract": EVENT_CONTRACT, "required_event_topic": FIELD_CONTROL_REQUIRED_EVENT_TOPIC, "allowed_database_backends": FIELD_CONTROL_ALLOWED_DATABASE_BACKENDS, "declared_dependencies": spec["dependencies"], "side_effects": ()}
    ok = not missing_fields and not foreign_tables and not undeclared_dependencies and not findings
    return {"ok": ok, "pbc": PBC_KEY, "feature_number": resolved.feature_number, "slug": resolved.slug, "title": resolved.title, "capability": resolved.as_traceability_row(), "payload": candidate, "evidence": evidence, "missing_fields": missing_fields, "foreign_tables": foreign_tables, "undeclared_dependencies": undeclared_dependencies, "findings": findings, "side_effects": ()}


def improve1_field_control_contract() -> dict[str, Any]:
    evaluations = tuple(evaluate_field_control(capability) for capability in FIELD_CONTROL_CAPABILITIES)
    blocking = tuple(item for item in evaluations if not item["ok"])
    return {"ok": not blocking, "pbc": PBC_KEY, "format": "appgen.field-service-management-improve1-control.v1", "capability_count": len(evaluations), "capabilities": evaluations, "owned_tables": FIELD_CONTROL_OWNED_TABLES, "declared_dependencies": FIELD_CONTROL_DECLARED_DEPENDENCIES, "allowed_database_backends": FIELD_CONTROL_ALLOWED_DATABASE_BACKENDS, "event_contract": EVENT_CONTRACT, "required_event_topic": FIELD_CONTROL_REQUIRED_EVENT_TOPIC, "stream_engine_picker_visible": False, "blocking_gaps": blocking, "side_effects": ()}


FIELD_CONTROL_FUNCTIONS = {capability.slug: (lambda payload=None, slug=capability.slug: evaluate_field_control(slug, payload)) for capability in FIELD_CONTROL_CAPABILITIES}
